// // This module disables the clock for a flip-flop based on a control signal.
module clock_gating_control(  
    input wire clk,  
    input wire enable,  
    input wire d,  
    output reg q  
);  
    always @(posedge clk) begin  
        if (enable) begin  
            q <= d;  
        end  
    end  
endmodule
